input.command:
echo "=== hostname ==="; hostname
echo "=== scheduler ==="; command -v bsub && echo "LSF present"; command -v sbatch && echo "Slurm present"
echo "=== LSF queues (if LSF) ==="; command -v bqueues >/dev/null && bqueues 2>/dev/null | head -20
echo "=== amrfinder ==="; command -v amrfinder amrfinder_update 2>/dev/null; 
echo "=== modules ==="; command -v module >/dev/null && (module avail 2>&1 | grep -i -E "amrfinder|ncbi|blast" | head) 
echo "=== conda ==="; command -v conda mamba 2>/dev/null
